from relay_protocol.gateway import EventGateway


def test_present_falsey_metadata_survives_the_wire_boundary():
    endpoint = EventGateway()
    event = {
        "type": "checkpoint",
        "body": {"cursor": "segment-a"},
        "attempt": 0,
        "durable": False,
        "trace": "",
    }
    assert endpoint.feed(endpoint.outbound(event)) == [event]


def test_utf8_payload_uses_the_same_frame_contract_as_ascii():
    endpoint = EventGateway()
    event = {
        "type": "label",
        "body": {"city": "M\u00fcnchen", "marker": "\u03bb"},
        "attempt": 1,
    }
    assert endpoint.feed(endpoint.outbound(event)) == [event]


def test_a_frame_can_arrive_across_unrelated_packet_boundaries():
    sender = EventGateway()
    receiver = EventGateway()
    event = {"type": "snapshot", "body": {"partition": "north", "rows": 8}}
    wire = sender.outbound(event)
    observed = []
    for chunk in (wire[:2], wire[2:7], wire[7:-3], wire[-3:]):
        observed.extend(receiver.feed(chunk))
    assert observed == [event]
